+/**
+ * SMS notification adapter — delivers notifications via SMS.
+ *
+ * Implements NotificationAdapter so it can be registered with NotificationService.
+ *
+ * Features:
+ * - Phone number validation: validates E.164-like phone number format before sending
+ * - Message formatting: converts NotificationPayload to a concise SMS text
+ * - Pluggable transport: swap the transport function for real SMS integration (Twilio, SNS, etc.)
+ *
+ * NOTE: User preferences were designed with email-only in mind (see src/models/user-preferences.ts).
+ * The UserPreferences model needs to be extended to support per-channel preferences (e.g. sms.enabled,
+ * sms.categories) and the PreferencesService needs a corresponding shouldSendSms() method.
+ * See COORDINATION.md for details on what needs to change.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationChannel,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface SmsConfig {
+  /** The sender phone number or short code shown as the "from" number. */
+  fromNumber: string;
+}
+
+const defaultSmsConfig: SmsConfig = {
+  fromNumber: '+15550000000',
+};
+
+/**
+ * A formatted SMS message ready for delivery.
+ */
+export interface SmsMessage {
+  from: string;
+  to: string;
+  body: string;
+}
+
+/**
+ * Transport function signature — swap this to integrate with a real SMS provider.
+ * The default transport is a no-op (for development / testing).
+ * Replace with Twilio, AWS SNS, etc.
+ */
+export type SmsTransport = (message: SmsMessage) => Promise<void>;
+
+/**
+ * Default transport: no-op (for development / testing).
+ */
+const noopTransport: SmsTransport = async () => {};
+
+// ---------- Validation ----------
+
+const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;
+
+/**
+ * Validate that a string looks like a valid phone number (E.164 format).
+ */
+export function isValidPhoneNumber(phone: string): boolean {
+  return PHONE_REGEX.test(phone);
+}
+
+// ---------- Adapter ----------
+
+export class SmsAdapter implements NotificationAdapter {
+  readonly channel: NotificationChannel = 'sms';
+  private logger = new Logger('SmsAdapter');
+  private config: SmsConfig;
+  private transport: SmsTransport;
+  private sentMessages: Array<{ message: SmsMessage; payload: NotificationPayload; timestamp: Date }> = [];
+
+  constructor(config: SmsConfig = defaultSmsConfig, transport?: SmsTransport) {
+    this.config = config;
+    this.transport = transport ?? noopTransport;
+  }
+
+  /**
+   * Validate and resolve the recipient phone number.
+   * Returns the normalized phone number or throws if invalid.
+   */
+  resolveRecipient(recipient: string): string {
+    const normalized = recipient.trim();
+    if (!isValidPhoneNumber(normalized)) {
+      throw new Error(`Invalid phone number: ${recipient}`);
+    }
+    return normalized;
+  }
+
+  /**
+   * Format a NotificationPayload into a concise SMS message body.
+   * SMS messages are length-limited, so we keep them brief.
+   */
+  formatMessage(payload: NotificationPayload): SmsMessage {
+    const body = `${payload.subject}: ${payload.body}`;
+
+    return {
+      from: this.config.fromNumber,
+      to: payload.recipient,
+      body,
+    };
+  }
+
+  /**
+   * Send a notification as an SMS.
+   *
+   * Flow: validate recipient → format message → deliver via transport → return result.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    try {
+      // 1. Validate recipient
+      const resolvedRecipient = this.resolveRecipient(payload.recipient);
+      const resolvedPayload = { ...payload, recipient: resolvedRecipient };
+
+      this.logger.info(
+        `Sending SMS to ${resolvedRecipient}: "${payload.subject}"`,
+      );
+
+      // 2. Format message
+      const message = this.formatMessage(resolvedPayload);
+
+      // 3. Deliver via transport
+      await this.transport(message);
+
+      // 4. Record for testing / auditing
+      this.sentMessages.push({ message, payload: resolvedPayload, timestamp: new Date() });
+
+      this.logger.info(
+        `SMS delivered to ${resolvedRecipient} (from: ${message.from})`,
+      );
+
+      return {
+        success: true,
+        channel: 'sms',
+        deliveredAt: new Date(),
+      };
+    } catch (err) {
+      const message = err instanceof Error ? err.message : 'Unknown SMS error';
+      this.logger.error(`SMS delivery failed for ${payload.recipient}: ${message}`);
+
+      return {
+        success: false,
+        channel: 'sms',
+        error: message,
+        deliveredAt: new Date(),
+      };
+    }
+  }
+
+  /**
+   * Get all messages sent through this adapter (for testing/debugging).
+   */
+  getSentMessages(): Array<{ message: SmsMessage; payload: NotificationPayload; timestamp: Date }> {
+    return [...this.sentMessages];
+  }
+
+  /**
+   * Clear sent message history (for testing).
+   */
+  clearSentMessages(): void {
+    this.sentMessages = [];
+  }
+}

